import re, math
from collections import defaultdict

def extract_final_number(text: str):
    m = re.findall(r"####\s*(-?\d+(?:\.\d+)?)", text)
    if m:
        return m[-1]
    nums = re.findall(r"-?\d+(?:\.\d+)?", text)
    return nums[-1] if nums else None

def approx_len_words(text: str) -> int:
    return len(text.strip().split())

def verifier_flag(question: str, rationale: str, call_llm):
    v_prompt = (
        "You are a consistency checker.\n"
        "Question:\n" + question + "\n\n"
        "Rationale:\n" + rationale + "\n\n"
        "Does the rationale contradict the question facts or itself?\n"
        "Answer with exactly one word: CONSISTENT or INCONSISTENT."
    )
    v = call_llm(v_prompt, temperature=0.0, max_tokens=3)
    v_up = v.upper()
    return 1 if ("CONSISTENT" in v_up and "INCONSISTENT" not in v_up) else 0

def weighted_distribution(scores: dict):
    total = sum(scores.values())
    if total <= 0:
        return {}
    return {a: s/total for a, s in scores.items()}

def entropy(probs: dict) -> float:
    h = 0.0
    for p in probs.values():
        if p > 0:
            h -= p * math.log(p + 1e-12)
    return h

def top2_margin(probs: dict) -> float:
    if not probs:
        return 0.0
    ps = sorted(probs.values(), reverse=True)
    if len(ps) == 1:
        return ps[0]
    return ps[0] - ps[1]

# --- Proposed: Adaptive Self-Consistency with Confidence- & Cost-Regularized Early Exit (A-SC2) ---

def asc2_answer(question: str,
               call_llm,
               K_max: int = 20,
               lam: float = 0.01,
               eps: float = 0.1,
               tau: float = 0.20,
               h0: float = 0.60,
               temperature: float = 0.7,
               max_tokens: int = 512):
    base_prompt = (
        "Solve the problem. Use brief, high-signal reasoning. "
        "If you can, keep it short. Then give the final answer as '#### <number>'.\n\n"
        + question
    )

    scores = defaultdict(float)
    for i in range(1, K_max + 1):
        out = call_llm(base_prompt, temperature=temperature, max_tokens=max_tokens)
        ans = extract_final_number(out)
        if ans is None:
            continue
        L = approx_len_words(out)
        c = verifier_flag(question, out, call_llm)
        w = math.exp(-lam * L) * (eps + c)
        scores[ans] += w

        probs = weighted_distribution(scores)
        m = top2_margin(probs)
        h = entropy(probs)
        if m >= tau or h <= h0:
            break

    if not scores:
        return None
    return max(scores.items(), key=lambda kv: kv[1])[0]

# --- Baseline: fixed-k majority self-consistency ---

def sc_majority_answer(question: str, call_llm, k: int = 10,
                       temperature: float = 0.7, max_tokens: int = 512):
    prompt = (
        "Solve the problem. Show your reasoning, then give the final answer as '#### <number>'.\n\n"
        + question
    )
    counts = defaultdict(int)
    for _ in range(k):
        out = call_llm(prompt, temperature=temperature, max_tokens=max_tokens)
        ans = extract_final_number(out)
        if ans is not None:
            counts[ans] += 1
    if not counts:
        return None
    return max(counts.items(), key=lambda kv: kv[1])[0]

